#include <bits/stdc++.h>
#define int long long
#define mk make_pair
#define PII pair<int,int>
#define FOR(i,j,k) for(int i=(j);i<=(k);++i)
#define ROF(i,j,k) for(int i=(j);i>=(k);--i)
#define FOI(a,b) for(auto a : b)
#define wh while
#define inf 0x3f3f3f3f3f3f3f3f
#define IOS ios::sync_with_stdio(false);cin.tie(0);cout.tie(0);
#define snd second
#define fst first
#define pb push_back
#define CI const int
#define NP namespace
using NP std;
int quickpow(int a,int b)
{
	int ans=1;
	wh(b)
	{
		if(b&1)ans=ans*a;
        a=a*a;
		b>>=1;
	}
	return ans;
}
CI MAXN=2e5+5;
int n,in[MAXN],out[MAXN],t=0,s[MAXN],ans[MAXN];
void fix(int x,int y)
{
    for(int i=x;i<=n*2;i+=(i&-i))
    {
        s[i]+=y;

    }
}
int get_sum(int x)
{
    int sum=0;
    for(int i=x;i>0;i-=(i&-i))
    {
        sum+=s[i];
    }
    return sum;
}
vector<int> g[MAXN];
PII a[MAXN];
void dfs(int u,int fa)
{
    in[u]=++t;
    FOI(s,g[u])
    {
        if(s==fa)continue;
        dfs(s,u);
    }
    out[u]=++t;
}
signed main(void)
{

    //freopen(".in","r",stdin);
    //freopen(".out","w",stdout);
	IOS
    cin>>n;
    FOR(i,1,n)
    {
        cin>>a[i].fst;
        a[i].snd=i;
    }
    FOR(i,2,n)
    {
        int x;
        cin>>x;
        g[x].pb(i);
        g[i].pb(x);
    }
    dfs(1,0);
    sort(a+1,a+n+1);
    FOR(i,1,n/2)
    {
        swap(a[i],a[n-i+1]);
    }
    for(int l=1,r=1;r<=n;++r)
    {
        wh(r>=l&&a[l].fst>a[r].fst)
        {
            fix(in[a[l].snd],1);
            ++l;
        }
        ans[a[r].snd]=get_sum(out[a[r].snd])-get_sum(in[a[r].snd]-1);
    }
    FOR(i,1,n)
    {
        cout<<ans[i]<<'\n';
    }
    return false;
}
